  "inlineSchema": "// Chiro City Health Facilities & HR Management System\n// Prisma schema - PostgreSQL\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============ RBAC ============\nmodel Role {\n  id          String       @id @default(uuid())\n  name        String       @unique\n  description String?\n  permissions Permission[]\n  users       User[]\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n}\n\nmodel Permission {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  description String?\n  roles       Role[]\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n}\n\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  name      String\n  roleId    String\n  role      Role     @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"users\")\n}\n\n// ============ Facilities ============\n// Status: DRAFT | SUBMITTED | APPROVED | ACTIVE | INACTIVE | SUSPENDED | TERMINATED\nmodel Facility {\n  id             String    @id @default(uuid())\n  name           String\n  type           String // HOSPITAL | CLINIC | HEALTH_CENTER | PHARMACY\n  registrationNo String?\n  licenseNo      String?\n  licenseExpiry  DateTime?\n  address        String?\n  phone          String?\n  email          String?\n  status         String    @default(\"DRAFT\") // DRAFT, SUBMITTED, APPROVED, ACTIVE, INACTIVE, SUSPENDED, TERMINATED\n  services       String? // JSON array of service names\n  legalInfo      String? // JSON for legal details\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  staff        StaffAssignment[]\n  staffMembers Staff[] // Staff with facilityId = this facility\n  documents    FacilityDocument[]\n  auditLogs    AuditLog[]         @relation(\"FacilityAudit\")\n\n  @@map(\"facilities\")\n}\n\nmodel FacilityDocument {\n  id         String   @id @default(uuid())\n  facilityId String\n  facility   Facility @relation(fields: [facilityId], references: [id], onDelete: Cascade)\n  name       String\n  type       String // license, registration, contract, etc.\n  filePath   String\n  mimeType   String\n  sizeBytes  Int?\n  uploadedAt DateTime @default(now())\n  uploadedBy String?\n\n  @@map(\"facility_documents\")\n}\n\n// ============ Staff ============\n// Status: DRAFT | SUBMITTED | APPROVED | ACTIVE | INACTIVE | SUSPENDED | TERMINATED\nmodel Staff {\n  id               String    @id @default(uuid())\n  employeeId       String    @unique\n  name             String\n  email            String\n  phone            String?\n  department       String?\n  designation      String\n  facilityId       String?\n  facility         Facility? @relation(fields: [facilityId], references: [id], onDelete: SetNull)\n  departmentName   String?\n  licenseNo        String?\n  licenseExpiry    DateTime?\n  status           String    @default(\"DRAFT\")\n  joiningDate      DateTime?\n  address          String?\n  emergencyContact String?\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n\n  assignments StaffAssignment[]\n  documents   StaffDocument[]\n  auditLogs   AuditLog[]        @relation(\"StaffAudit\")\n\n  @@map(\"staff\")\n}\n\nmodel StaffAssignment {\n  id         String   @id @default(uuid())\n  staffId    String\n  staff      Staff    @relation(fields: [staffId], references: [id], onDelete: Cascade)\n  facilityId String\n  facility   Facility @relation(fields: [facilityId], references: [id], onDelete: Cascade)\n  department String?\n  assignedAt DateTime @default(now())\n  assignedBy String?\n\n  @@unique([staffId, facilityId])\n  @@map(\"staff_assignments\")\n}\n\nmodel StaffDocument {\n  id         String   @id @default(uuid())\n  staffId    String\n  staff      Staff    @relation(fields: [staffId], references: [id], onDelete: Cascade)\n  name       String\n  type       String\n  filePath   String\n  mimeType   String\n  sizeBytes  Int?\n  uploadedAt DateTime @default(now())\n  uploadedBy String?\n\n  @@map(\"staff_documents\")\n}\n\n// ============ Notifications ============\nmodel Notification {\n  id        String    @id @default(uuid())\n  type      String // LICENSE_EXPIRY | STAFF_ASSIGNMENT | FACILITY_ACTIVATION | etc.\n  title     String\n  message   String\n  channel   String // EMAIL | SMS\n  recipient String?\n  sentAt    DateTime?\n  readAt    DateTime?\n  metadata  String? // JSON\n  createdAt DateTime  @default(now())\n\n  @@map(\"notifications\")\n}\n\n// ============ Audit ============\nmodel AuditLog {\n  id         String    @id @default(uuid())\n  action     String\n  entity     String // Facility | Staff | User | etc.\n  entityId   String?\n  facilityId String?\n  facility   Facility? @relation(\"FacilityAudit\", fields: [facilityId], references: [id], onDelete: SetNull)\n  staffId    String?\n  staff      Staff?    @relation(\"StaffAudit\", fields: [staffId], references: [id], onDelete: SetNull)\n  userId     String?\n  payload    String? // JSON\n  createdAt  DateTime  @default(now())\n\n  @@map(\"audit_logs\")\n}\n",
